namespace sv_2f54340afd2e4b9ea34089436f2001e8.Services;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class NotificationItem
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

/// <summary>
/// Scoped per-circuit service that holds notification state and notifies
/// all subscribed components when any mutation occurs.
/// </summary>
public class NotificationHub
{
    private readonly List<NotificationItem> _notifications = [];
    private readonly object _lock = new();

    /// <summary>
    /// Subscribers attach here to be notified on any state change.
    /// Handlers may be invoked from background threads, so subscribers
    /// must marshal to the UI thread via InvokeAsync.
    /// </summary>
    public event Action? OnChange;

    public IReadOnlyList<NotificationItem> Notifications
    {
        get
        {
            lock (_lock)
            {
                return _notifications.ToList();
            }
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock)
        {
            return _notifications.Count(n => !n.IsRead);
        }
    }

    public void AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Add(new NotificationItem
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        OnChange?.Invoke();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var item = _notifications.FirstOrDefault(n => n.Id == id);
            if (item is not null)
                item.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications)
                n.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        OnChange?.Invoke();
    }
}

namespace sv_2f54340afd2e4b9ea34089436f2001e8.Services;

/// <summary>
/// Scoped service that simulates server-push events by adding a random
/// notification every 15 seconds. Start/Stop are called by the dashboard
/// component. The timer fires on a thread-pool thread, so all
/// NotificationHub.OnChange subscribers must marshal to the UI thread.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private Timer? _timer;
    private static readonly Random _rng = new();

    private static readonly (string Title, string Message, Severity Severity)[] Templates =
    [
        ("Disk space low", "Server disk usage exceeded 90%.", Severity.Critical),
        ("Build failed", "CI pipeline #4821 failed on main.", Severity.Critical),
        ("CPU spike detected", "CPU usage above 95% for 2 minutes.", Severity.Critical),
        ("New deployment", "v2.4.1 deployed to staging.", Severity.Info),
        ("User signup", "A new user registered.", Severity.Info),
        ("Backup complete", "Nightly backup finished successfully.", Severity.Info),
        ("SSL certificate expiry", "Certificate expires in 7 days.", Severity.Warning),
        ("Memory usage high", "Memory usage at 85%.", Severity.Warning),
        ("Slow query detected", "Query took 12s on orders table.", Severity.Warning),
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        _timer ??= new Timer(_ =>
        {
            var template = Templates[_rng.Next(Templates.Length)];
            _hub.AddNotification(template.Title, template.Message, template.Severity);
        }, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    public void Stop()
    {
        _timer?.Change(Timeout.Infinite, Timeout.Infinite);
    }

    public void Dispose()
    {
        _timer?.Dispose();
        _timer = null;
    }
}

