@* Interactive island embedded in the static NavMenu layout.
   Uses its own @rendermode so it can subscribe to the scoped NotificationHub
   and re-render when unread count changes — even from background threads. *@
@rendermode InteractiveServer
@inject sv_2f54340afd2e4b9ea34089436f2001e8.Services.NotificationHub Hub
@implements IDisposable

<a class="nav-link" href="notifications" style="position: relative;">
    <span class="bi bi-bell-nav-menu" aria-hidden="true"></span> Notifications
    @if (_unreadCount > 0)
    {
        <span class="badge bg-danger rounded-pill" style="position: absolute; top: 0.2rem; left: 1.6rem; font-size: 0.7rem;">
            @_unreadCount
        </span>
    }
</a>

@code {
    private int _unreadCount;
    private Action? _handler;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        // Wrap in InvokeAsync because OnChange may fire from a timer thread.
        _handler = () => InvokeAsync(() =>
        {
            _unreadCount = Hub.GetUnreadCount();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@inject sv_2f54340afd2e4b9ea34089436f2001e8.Services.NotificationHub Hub
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Notifications</h1>
    <button class="btn btn-outline-primary btn-sm" @onclick="Hub.MarkAllRead" disabled="@(Hub.GetUnreadCount() == 0)">
        Mark All Read
    </button>
</div>

@if (!_notifications.Any())
{
    <p class="text-muted">No notifications yet.</p>
}
else
{
    @foreach (var group in _notifications
        .GroupBy(n => n.Severity)
        .OrderByDescending(g => g.Key))
    {
        <h4 class="mt-4">
            <span class="badge @SeverityBadgeClass(group.Key)">@group.Key</span>
        </h4>
        <ul class="list-group mb-3">
            @foreach (var n in group.OrderByDescending(n => n.Timestamp))
            {
                <li class="list-group-item d-flex justify-content-between align-items-start @(n.IsRead ? "" : "list-group-item-light fw-bold")">
                    <div class="ms-2 me-auto">
                        <div>@n.Title</div>
                        <small class="text-muted fw-normal">@n.Message</small>
                        <br />
                        <small class="text-muted fw-normal">@n.Timestamp.ToString("g")</small>
                    </div>
                    <div class="btn-group btn-group-sm">
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-outline-success btn-sm" @onclick="() => Hub.MarkAsRead(n.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-outline-danger btn-sm" @onclick="() => Hub.DismissNotification(n.Id)">
                            Dismiss
                        </button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
