   Subscribes to the same NotificationHub so it stays in sync with the
   bell badge and the /notifications page. *@
@inject sv_2f54340afd2e4b9ea34089436f2001e8.Services.NotificationHub Hub
@implements IDisposable

<div class="card">
    <div class="card-header d-flex justify-content-between align-items-center">
