@code {
    private List<sv_2f54340afd2e4b9ea34089436f2001e8.Services.NotificationItem> _recentUnread = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        Refresh();
        _handler = () => InvokeAsync(() =>
        {
            Refresh();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void Refresh()
    {
        _recentUnread = Hub.Notifications
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
