        sv_2f54340afd2e4b9ea34089436f2001e8.Services.Severity.Critical => "bg-danger",
        sv_2f54340afd2e4b9ea34089436f2001e8.Services.Severity.Warning => "bg-warning text-dark",
        _ => "bg-info text-dark"
    };
}

