@* Shows the 3 most recent unread notifications on the dashboard.
   Subscribes to the same NotificationHub so it stays in sync with the
   bell badge and the /notifications page. *@
@inject sv_2f54340afd2e4b9ea34089436f2001e8.Services.NotificationHub Hub
@implements IDisposable

<div class="card">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Recent Unread Notifications</strong>
        <span class="badge bg-secondary">@_recentUnread.Count unread</span>
    </div>
    <div class="card-body">
        @if (!_recentUnread.Any())
        {
            <p class="text-muted mb-0">All caught up!</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var n in _recentUnread)
                {
                    <li class="list-group-item d-flex justify-content-between align-items-start">
                        <div class="ms-2 me-auto">
                            <span class="badge @SeverityClass(n.Severity) me-1">@n.Severity</span>
                            @n.Title
                            <br />
                            <small class="text-muted">@n.Message</small>
                        </div>
                        <button class="btn btn-outline-danger btn-sm" @onclick="() => Hub.DismissNotification(n.Id)">
                            Dismiss
                        </button>
                    </li>
                }
            </ul>
        }
    </div>
</div>

@code {
    private List<sv_2f54340afd2e4b9ea34089436f2001e8.Services.NotificationItem> _recentUnread = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        Refresh();
        _handler = () => InvokeAsync(() =>
        {
            Refresh();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void Refresh()
    {
        _recentUnread = Hub.Notifications
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }

    private static string SeverityClass(sv_2f54340afd2e4b9ea34089436f2001e8.Services.Severity s) => s switch
    {
        sv_2f54340afd2e4b9ea34089436f2001e8.Services.Severity.Critical => "bg-danger",
        sv_2f54340afd2e4b9ea34089436f2001e8.Services.Severity.Warning => "bg-warning text-dark",
        _ => "bg-info text-dark"
    };
}

